var ADDONS_REGISTRY_URL="../../addons/addons.json",ADDON_CACHE_KEY="acadon_addons_registry",ADDON_CONTENT_PREFIX="acadon_addon_",ADDON_CACHE_TTL=864e5;async function getAddonsRegistry(){try{var t=localStorage.getItem(ADDON_CACHE_KEY);if(t){var a=JSON.parse(t);if(Date.now()-a.timestamp<ADDON_CACHE_TTL)return a.data}}catch(t){}var e=await fetch(ADDONS_REGISTRY_URL);if(!e.ok)return[];var r=await e.json();try{localStorage.setItem(ADDON_CACHE_KEY,JSON.stringify({data:r,timestamp:Date.now()}))}catch(t){}return r}async function getAddonHtml(t,a){for(var e=null,r=0;r<a.length;r++)if(a[r].id===t){e=a[r];break}if(!e)return"";var n=ADDON_CONTENT_PREFIX+t;try{var o=localStorage.getItem(n);if(o){var i=JSON.parse(o);if(Date.now()-i.timestamp<ADDON_CACHE_TTL)return i.content}}catch(t){}var s="../../addons/"+e.htmlFile,c=await fetch(s);if(!c.ok)return"";var d=await c.text();try{localStorage.setItem(n,JSON.stringify({content:d,timestamp:Date.now()}))}catch(t){}return d}async function composeAddonsHtml(t){if(!t||0===t.length)return"";for(var a=await getAddonsRegistry(),e=[],r=0;r<t.length;r++){var n=await getAddonHtml(t[r],a);n&&e.push(n)}return e.join("\n")}